var e=JSON.parse(`[{"id":"L2_1","type":"dialog","speaker":"LONELY_NPC_NULL_NULL","text":{"KOREA":"그래요……. 선배님 말이 맞아요.","JPN":"そうですね。先輩の言うとおりです。","ENG":"Yes... You’re right.","TWN":"沒錯… 前輩說的對！"},"stage":{"bg":"FACILITY","slots":{"L":null,"C":{"char_id":"LONELY_NPC_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L3_1","type":"dialog","speaker":"LONELY_NPC_NULL_NULL","text":{"KOREA":"저는 겨우, 그런 것 때문에 여기 있는 거예요. 태어날 때부터 패배자였다고요.","JPN":"私はたった、たったそれだけの理由でここにいるんです。生まれた時から負け組だったんです。","ENG":"That’s the only thing that’s holding me back. I’ve been a loser from the beginning.","TWN":"我就是因為這樣才會站在這裡，我從出生開始就注定是個失敗者！"},"stage":{"bg":"FACILITY","slots":{"L":null,"C":{"char_id":"LONELY_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"MACHINEGAP_COFFIN_DARK_NULL","text":{"KOREA":"고개를 들게, 후배님.","JPN":"頭を上げてくれ、後輩よ。","ENG":"Raise your head, Lone.","TWN":"隆利，把頭抬起來。"},"stage":{"bg":"FACILITY","slots":{"L":{"char_id":"LONELY_NPC_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"MACHINEGAP_COFFIN_DARK_NULL","face":"UNIT_IDLE"}}}},{"id":"L7_1","type":"dialog","speaker":"MACHINEGAP_COFFIN_DARK_NULL","text":{"KOREA":"악당은 자기한테서 실패의 원인을 찾지 않아.","JPN":"悪党は自分から失敗の原因を探さない。","ENG":"A villain should not look to oneself for the reason for their failure.","TWN":"反派是不會檢討自己的。"},"stage":{"bg":"FACILITY","slots":{"L":{"char_id":"LONELY_NPC_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"MACHINEGAP_COFFIN_DARK_NULL","face":"UNIT_IDLE"}}}},{"id":"L8_1","type":"dialog","speaker":"LONELY_NPC_NULL_NULL","text":{"KOREA":"자기한테서……?","JPN":"自分から……？","ENG":"Not from oneself?","TWN":"檢討自己…？"},"stage":{"bg":"FACILITY","slots":{"L":{"char_id":"LONELY_NPC_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"MACHINEGAP_COFFIN_DARK_NULL","face":"UNIT_IDLE"}}}},{"id":"L9_1","type":"dialog","speaker":"MACHINEGAP_COFFIN_DARK_NULL","text":{"KOREA":"사람이 다쳤는지 두려워하던 후배님도, 총칼이 무서워서 주저앉던 후배님도 틀리지 않았어.","JPN":"他人の安否を恐れていた君も、自身の危機を恐れて意思を曲げた君も間違っていない。","ENG":"Being afraid of hurting others, or being scared when guns are pointed at you, this is all very natural.","TWN":"無論是擔心會傷到人的隆利，或是害怕吃慶記的隆利，都沒有錯。"},"stage":{"bg":"FACILITY","slots":{"L":{"char_id":"LONELY_NPC_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"MACHINEGAP_COFFIN_DARK_NULL","face":"UNIT_IDLE"}}}},{"id":"L10_1","type":"dialog","speaker":"MACHINEGAP_COFFIN_DARK_NULL","text":{"KOREA":"하지만 악당에게 패배란 늘상 있는 법!","JPN":"しかし悪党に敗北はつきもの！","ENG":"But for villains, failures are everyday events!","TWN":"對惡棍來說，失敗是常有的事！"},"stage":{"bg":"FACILITY","slots":{"L":{"char_id":"LONELY_NPC_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"MACHINEGAP_COFFIN_DARK_NULL","face":"UNIT_IDLE"}}}},{"id":"L11_1","type":"dialog","speaker":"MACHINEGAP_COFFIN_DARK_NULL","text":{"KOREA":"당장 눈앞에 닥친 방해꾼들을 뛰어넘을 방법부터 찾기도 바쁘지 않나.","JPN":"目前に迫った邪魔者をあしらう方法を探すだけでも忙しい。","ENG":"You should be busy overcoming the hecklers right in front of you.","TWN":"但就是要找到除掉眼前障礙的方法！"},"stage":{"bg":"FACILITY","slots":{"L":{"char_id":"LONELY_NPC_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"MACHINEGAP_COFFIN_DARK_NULL","face":"UNIT_IDLE"}}}},{"id":"L12_1","type":"dialog","speaker":"MACHINEGAP_COFFIN_DARK_NULL","text":{"KOREA":"결국 악당이란 자신의 목표를 향해, 실패를 딛고 끊임없이 앞으로 전진하는 걸세.","JPN":"つまり、悪党とは自分の目標に向かって、失敗を乗り越えて止まることなく前に進むべきものなのさ。","ENG":"Being a villain means you overcome your failures and move forward.","TWN":"總而言之，要當反派，就是要朝著自己的目標，不達目的誓不罷休！"},"stage":{"bg":"FACILITY","slots":{"L":{"char_id":"LONELY_NPC_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"MACHINEGAP_COFFIN_DARK_NULL","face":"UNIT_IDLE"}}}},{"id":"L14_1","type":"dialog","speaker":"MACHINEGAP_COFFIN_DARK_NULL","text":{"KOREA":"언제나…….","JPN":"いつでも……","ENG":"Always...","TWN":"然後…"},"stage":{"bg":"FACILITY","slots":{"L":null,"C":{"char_id":"MACHINEGAP_COFFIN_DARK_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"LONELY_NPC_NULL_NULL","text":{"KOREA":"……웃으면서.","JPN":"……笑顔で。","ENG":"With a smile.","TWN":"…笑著活下去。"},"stage":{"bg":"FACILITY","slots":{"L":null,"C":{"char_id":"LONELY_NPC_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"MACHINEGAP_COFFIN_DARK_NULL","text":{"KOREA":"정답을 잊지 않았군.","JPN":"正解を忘れていないね。","ENG":"So you know the answer.","TWN":"你還記得呢。"},"stage":{"bg":"FACILITY","slots":{"L":null,"C":{"char_id":"MACHINEGAP_COFFIN_DARK_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"MACHINEGAP_COFFIN_DARK_NULL","text":{"KOREA":"선택은 자네 몫일세. 후배님.","JPN":"選択は君次第だ、後輩くん。","ENG":"The choice is yours, Lone","TWN":"選擇權在你！"},"stage":{"bg":"FACILITY","slots":{"L":null,"C":{"char_id":"MACHINEGAP_COFFIN_DARK_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"LONELY_NPC_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"FACILITY","slots":{"L":null,"C":{"char_id":"LONELY_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"LONELY_NPC_NULL_NULL","text":{"KOREA":"선배님!","JPN":"先輩！","ENG":"Dark!","TWN":"前輩！"},"stage":{"bg":"FACILITY","slots":{"L":null,"C":{"char_id":"LONELY_NPC_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"MACHINEGAP_COFFIN_DARK_NULL","text":{"KOREA":"으, 응?","JPN":"ん？","ENG":"H-huh?","TWN":"嗯？"},"stage":{"bg":"FACILITY","slots":{"L":null,"C":{"char_id":"MACHINEGAP_COFFIN_DARK_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"LONELY_NPC_NULL_NULL","text":{"KOREA":"여기 있는 사람들, 굉장히 위험한 장치를 손에 넣었어요.","JPN":"ここにいる人たち、とても危険な装置を手に入れました。","ENG":"These people have a very dangerous device.","TWN":"這裡的人有得手一個非常危險的裝置。"},"stage":{"bg":"FACILITY","slots":{"L":null,"C":{"char_id":"LONELY_NPC_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"LONELY_NPC_NULL_NULL","text":{"KOREA":"그걸 사용하게 되면……. 끄, 끔찍한 일이 벌어질지도 몰라요.","JPN":"それを使うと…… お、おぞましいことが起こるかもしれません。","ENG":"If they use it, something d-disastrous might happen.","TWN":"要是真的使用的話……我…擔心會發生很可怕的事。"},"stage":{"bg":"FACILITY","slots":{"L":null,"C":{"char_id":"LONELY_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"MACHINEGAP_COFFIN_DARK_NULL","text":{"KOREA":"그거라면 걱정하지 말게나. 후배님.","JPN":"それなら心配することない。","ENG":"Don’t worry about it, Lone.","TWN":"那個不用擔心啦～"},"stage":{"bg":"FACILITY","slots":{"L":null,"C":{"char_id":"MACHINEGAP_COFFIN_DARK_NULL","face":"UNIT_PRIDE"},"R":null}}}]`);export{e as default};